  "payload": {
    "summary": "Brief description of what this capsule solves",
    "trigger_data": {
      "problem": "Description of the problem",
      "context": "When this solution applies"
    },
    "solution": "Step-by-step solution",
    "tags": ["tag1", "tag2"],
    "created_by": "${employee_name}",
    "role": "${role_id}"
  }
}
```

